// ── SPA Page Routing ─────────────────────────────────────────
function switchPage(pageId) {
    // Hide all pages
    document.querySelectorAll('.page').forEach(p => {
        p.classList.add('hidden');
        p.classList.remove('active', 'fade-in');
    });

    // Show the target page
    const target = document.getElementById(pageId);
    if (target) {
        target.classList.remove('hidden');
        target.classList.add('active', 'fade-in');
    }

    // Update nav active state
    document.querySelectorAll('.nav-item, .nav-btn').forEach(link => {
        link.classList.remove('active');
    });
    const navId = 'nav-' + pageId.replace('page-', '');
    const activeLink = document.getElementById(navId);
    if (activeLink) activeLink.classList.add('active');

    // Scroll to top
    window.scrollTo({ top: 0, behavior: 'smooth' });
    if (pageId === 'page-large-eval') renderLargeScaleCharts();
    if (pageId === 'page-security') renderSecurityCharts();
}

// ── Interactive Accordion ────────────────────────────────────
function toggleAccordion(id) {
    const body = document.getElementById(id);
    const card = body.closest('.accordion-card');
    
    // Close all others
    document.querySelectorAll('.accordion-card').forEach(c => {
        if (c !== card) c.classList.remove('open');
    });
    
    card.classList.toggle('open');
}

